+const needsSameOrigin = (src: string | undefined): boolean => {
+  if (!src) {
+    return false;
+  }
+  try {
+    const url = new URL(src);
+    return ALLOWED_SAME_ORIGIN_DOMAINS.some(
+      (domain) =>
+        url.hostname === domain || url.hostname.endsWith(`.${domain}`),
+    );
