+
+const sanitizeHTMLAttribute = (value: string): string => {
+  return value
+    .replace(/&/g, "&amp;")
+    .replace(/"/g, "&quot;")
+    .replace(/'/g, "&#x27;")
+    .replace(/</g, "&lt;")
+    .replace(/>/g, "&gt;");
+};
+
+const constructSrcdoc = (content: string): string => {
+  // Parse the content and reconstruct it safely rather than
+  // rendering untrusted HTML verbatim
+  const parser = new DOMParser();
+  const doc = parser.parseFromString(content, "text/html");
+
+  // Only allow specific safe elements and attributes
+  const allowedTags = new Set([
+    "html",
+    "head",
+    "body",
+    "style",
+    "div",
+    "span",
+    "p",
+    "a",
+    "img",
+    "blockquote",
+    "pre",
+    "code",
+  ]);
+
+  const allowedAttributes = new Set([
+    "class",
+    "style",
+    "href",
+    "src",
+    "alt",
+    "title",
+    "width",
+    "height",
+  ]);
+
+  const sanitizeNode = (node: Node): string => {
+    if (node.nodeType === Node.TEXT_NODE) {
+      return sanitizeHTMLAttribute(node.textContent || "");
+    }
+    if (node.nodeType !== Node.ELEMENT_NODE) {
+      return "";
+    }
+    const el = node as Element;
+    const tagName = el.tagName.toLowerCase();
+    if (!allowedTags.has(tagName)) {
+      // Still process children
+      return Array.from(el.childNodes).map(sanitizeNode).join("");
+    }
+
+    const attrs: string[] = [];
+    for (const attr of Array.from(el.attributes)) {
+      if (allowedAttributes.has(attr.name.toLowerCase())) {
+        const sanitizedValue = sanitizeHTMLAttribute(attr.value);
+        // Block javascript: URLs
+        if (
+          (attr.name.toLowerCase() === "href" ||
+            attr.name.toLowerCase() === "src") &&
+          /^\s*javascript\s*:/i.test(attr.value)
+        ) {
+          continue;
+        }
+        attrs.push(`${attr.name.toLowerCase()}="${sanitizedValue}"`);
+      }
+    }
+
+    const attrStr = attrs.length > 0 ? ` ${attrs.join(" ")}` : "";
+    const children = Array.from(el.childNodes).map(sanitizeNode).join("");
+
+    if (tagName === "style") {
+      // For style tags, use textContent directly (CSS, not HTML)
+      return `<style>${el.textContent || ""}</style>`;
+    }
+
+    return `<${tagName}${attrStr}>${children}</${tagName}>`;
+  };
+
