+'use strict';
+
+function htmlSanitize(html) {
+	if (!html) return html;
+
+	// Remove all on* event handlers (onclick, onerror, onload, onmouseover, etc.)
+	html = html.replace(/\s+on\w+\s*=\s*("[^"]*"|'[^']*'|[^\s>]*)/gi, '');
+
+	// Remove javascript: URLs in href and src attributes
+	html = html.replace(/(href|src)\s*=\s*["']\s*javascript\s*:[^"']*/gi, '$1=""');
+
+	// Remove data: URLs in src attributes (can be used for XSS)
+	html = html.replace(/src\s*=\s*["']\s*data\s*:[^"']*/gi, 'src=""');
+
+	// Remove vbscript: URLs
+	html = html.replace(/(href|src)\s*=\s*["']\s*vbscript\s*:[^"']*/gi, '$1=""');
+
+	// Remove <script> tags and their content
+	html = html.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
+
+	// Remove standalone <script> opening/closing tags
+	html = html.replace(/<\/?script[^>]*>/gi, '');
+
+	// Remove <iframe> tags
+	html = html.replace(/<iframe\b[^<]*(?:(?!<\/iframe>)<[^<]*)*<\/iframe>/gi, '');
+	html = html.replace(/<\/?iframe[^>]*>/gi, '');
+
+	return html;
+}
+
+module.exports = htmlSanitize;

