+/// Verify the QE Report fields against the QE Identity policy constraints.
+fn verify_qe_report_against_identity(quote: &Quote, collateral: &Collateral) -> Result<()> {
+    let qe_identity: QeIdentity = serde_json::from_str(&collateral.qe_identity)
+        .context("Failed to parse QE Identity JSON")?;
+
+    let qe_report = &quote.qe_report;
+
+    // Verify MRSIGNER matches
+    let expected_mrsigner = hex::decode(&qe_identity.mrsigner)
+        .context("Failed to decode QE Identity MRSIGNER")?;
+    if qe_report.mrsigner.as_slice() != expected_mrsigner.as_slice() {
+        bail!(
+            "QE Report MRSIGNER mismatch: expected {}, got {}",
+            qe_identity.mrsigner,
+            hex::encode(&qe_report.mrsigner)
+        );
+    }
+
+    // Verify ISVPRODID matches
+    if qe_report.isv_prod_id != qe_identity.isvprodid {
+        bail!(
+            "QE Report ISVPRODID mismatch: expected {}, got {}",
+            qe_identity.isvprodid,
+            qe_report.isv_prod_id
+        );
+    }
+
+    // Verify Attributes match with mask
+    if let Some(ref attributes_mask) = qe_identity.attributes_mask {
+        let mask = hex::decode(attributes_mask).context("Failed to decode attributes mask")?;
+        let expected_attributes = hex::decode(&qe_identity.attributes)
+            .context("Failed to decode QE Identity attributes")?;
+        let masked_report_attrs: Vec<u8> = qe_report.attributes.iter().zip(mask.iter()).map(|(a, m)| a & m).collect();
+        let masked_expected_attrs: Vec<u8> = expected_attributes.iter().zip(mask.iter()).map(|(a, m)| a & m).collect();
+        if masked_report_attrs != masked_expected_attrs {
+            bail!("QE Report attributes do not match QE Identity policy after masking");
+        }
+    }
+
+    // Verify miscselect with mask
+    if let Some(ref miscselect_mask) = qe_identity.miscselect_mask {
+        let mask = u32::from_str_radix(miscselect_mask.trim_start_matches("0x"), 16)
+            .context("Failed to parse miscselect mask")?;
+        let expected_miscselect = u32::from_str_radix(
+            qe_identity.miscselect.trim_start_matches("0x"),
+            16,
+        )
+        .context("Failed to parse QE Identity miscselect")?;
+        if (qe_report.misc_select & mask) != (expected_miscselect & mask) {
+            bail!("QE Report miscselect does not match QE Identity policy after masking");
+        }
+    }
+
+    Ok(())
+}
