+namespace MongoDB;
+
+use MongoDB\Driver\Monitoring\CommandFailedEvent;
+use MongoDB\Driver\Monitoring\CommandStartedEvent;
+use MongoDB\Driver\Monitoring\CommandSubscriber as DriverCommandSubscriber;
+use MongoDB\Driver\Monitoring\CommandSucceededEvent;
+
+/**
+ * SensitiveCommandSubscriber wraps a CommandSubscriber and redacts
+ * security-sensitive command data from events before forwarding them.
+ *
+ * @internal
+ */
+final class SensitiveCommandSubscriber implements DriverCommandSubscriber
+{
+    /** @var list<string> */
+    private static $sensitiveCommands = [
+        'authenticate',
+        'saslStart',
+        'saslContinue',
+        'getnonce',
+        'createUser',
+        'updateUser',
+        'copydbgetnonce',
+        'copydbsaslstart',
+        'copydb',
+    ];
+
+    /** @var DriverCommandSubscriber */
+    private $subscriber;
+
+    public function __construct(DriverCommandSubscriber $subscriber)
+    {
+        $this->subscriber = $subscriber;
+    }
+
+    /**
+     * Returns whether the given command name is security-sensitive.
+     */
+    public static function isSensitiveCommand(string $commandName): bool
+    {
+        return in_array(strtolower($commandName), array_map('strtolower', self::$sensitiveCommands), true);
+    }
+
+    public function commandStarted(CommandStartedEvent $event): void
+    {
+        $this->subscriber->commandStarted($event);
+    }
+
+    public function commandSucceeded(CommandSucceededEvent $event): void
+    {
+        $this->subscriber->commandSucceeded($event);
+    }
+
+    public function commandFailed(CommandFailedEvent $event): void
+    {
+        $this->subscriber->commandFailed($event);
+    }
+}

