+/**
+ * Sanitize message content by removing platform-specific privileged tags
+ * that could be abused by unprivileged users through bot commands.
+ */
+export function sanitizeMessage(content: string): string {
+  let sanitized = content;
+  // Remove <qqbot-at-everyone /> tags (self-closing and paired variants)
+  sanitized = sanitized.replace(/<qqbot-at-everyone\s*\/?\s*>/gi, '');
+  sanitized = sanitized.replace(/<qqbot-at-everyone\s*>[^<]*<\/qqbot-at-everyone\s*>/gi, '');
+  return sanitized;
+}
+
+export default sanitizeMessage;

