+/* @flow */
+
+const dns = require('dns');
+
+// Cache DNS resolutions to prevent TOCTOU race conditions (CVE-2019-15608)
+// where DNS could resolve to a different IP between check and use.
+const dnsCache: Map<string, {address: string, expires: number}> = new Map();
+const DNS_CACHE_TTL = 30 * 1000; // 30 seconds
+
+export function resolveWithRecordType(hostname: string): Promise<string> {
+  const cached = dnsCache.get(hostname);
+  const now = Date.now();
+  if (cached && cached.expires > now) {
+    return Promise.resolve(cached.address);
+  }
+
+  return new Promise((resolve, reject) => {
+    dns.resolve(hostname, (err, addresses) => {
+      if (err) {
+        reject(err);
+        return;
+      }
+      if (addresses && addresses.length > 0) {
+        dnsCache.set(hostname, {address: addresses[0], expires: now + DNS_CACHE_TTL});
+        resolve(addresses[0]);
+      } else {
+        reject(new Error(`Could not resolve hostname: ${hostname}`));
+      }
+    });
+  });
+}
