@@ -0,0 +1,62 @@
+import { ValidationError } from '../errors/validation-error';
+
+/**
+ * Validates Python code before execution to prevent sandbox escapes.
+ * This is a defense-in-depth measure; the runtime sandbox is the primary control.
+ */
+export function validatePythonCode(code: string): void {
+	const disallowedPatterns: Array<{ pattern: RegExp; message: string }> = [
+		{
+			pattern: /__subclasses__/,
+			message: 'Access to __subclasses__ is not allowed',
+		},
+		{
+			pattern: /__bases__/,
+			message: 'Access to __bases__ is not allowed',
+		},
+		{
+			pattern: /__mro__/,
+			message: 'Access to __mro__ is not allowed',
+		},
+		{
+			pattern: /__globals__/,
+			message: 'Access to __globals__ is not allowed',
+		},
+		{
+			pattern: /__code__/,
+			message: 'Access to __code__ is not allowed',
+		},
+		{
+			pattern: /__builtins__/,
+			message: 'Access to __builtins__ is not allowed',
+		},
+		{
+			pattern: /\beval\s*\(/,
+			message: 'Use of eval() is not allowed',
+		},
+		{
+			pattern: /\bexec\s*\(/,
+			message: 'Use of exec() is not allowed',
+		},
+		{
+			pattern: /\bcompile\s*\(/,
+			message: 'Use of compile() is not allowed',
+		},
+		{
+			pattern: /\b__import__\s*\(/,
+			message: 'Direct use of __import__() is not allowed; use import statements instead',
+		},
+		{
+			pattern: /\bgetattr\s*\(/,
+			message: 'Use of getattr() is not allowed',
+		},
+		{
+			pattern: /\bsetattr\s*\(/,
+			message: 'Use of setattr() is not allowed',
+		},
+		{
+			pattern: /\bdelattr\s*\(/,
+			message: 'Use of delattr() is not allowed',
+		},
+	];
+
+	for (const { pattern, message } of disallowedPatterns) {
+		if (pattern.test(code)) {
+			throw new ValidationError(message);
+		}
+	}
+}
