+import { validatePythonCode } from '../python-validator';
+
+describe('validatePythonCode', () => {
+	it('should allow safe code', () => {
+		expect(() => validatePythonCode('x = 1 + 2')).not.toThrow();
+		expect(() => validatePythonCode('import json\njson.dumps({"a": 1})')).not.toThrow();
+		expect(() => validatePythonCode('result = [i for i in range(10)]')).not.toThrow();
+	});
+
+	it('should reject __subclasses__', () => {
+		expect(() => validatePythonCode('().__class__.__subclasses__()')).toThrow();
+	});
+
+	it('should reject __bases__', () => {
+		expect(() => validatePythonCode('().__class__.__bases__')).toThrow();
+	});
+
+	it('should reject __mro__', () => {
+		expect(() => validatePythonCode('type.__mro__')).toThrow();
+	});
+
+	it('should reject __globals__', () => {
+		expect(() => validatePythonCode('func.__globals__')).toThrow();
+	});
+
+	it('should reject __code__', () => {
+		expect(() => validatePythonCode('func.__code__')).toThrow();
+	});
+
+	it('should reject __builtins__', () => {
+		expect(() => validatePythonCode('__builtins__')).toThrow();
+	});
+
+	it('should reject eval()', () => {
+		expect(() => validatePythonCode('eval("1+1")')).toThrow();
+	});
+
+	it('should reject exec()', () => {
+		expect(() => validatePythonCode('exec("print(1)")')).toThrow();
+	});
+
+	it('should reject __import__()', () => {
+		expect(() => validatePythonCode('__import__("os")')).toThrow();
+	});
+
+	it('should reject getattr/setattr/delattr', () => {
+		expect(() => validatePythonCode('getattr(obj, "attr")')).toThrow();
+		expect(() => validatePythonCode('setattr(obj, "attr", val)')).toThrow();
+		expect(() => validatePythonCode('delattr(obj, "attr")')).toThrow();
+	});
+});

